// Import required libraries
const ethers = require('ethers');
const fs = require('fs');

// Set provider (Replace with your own)
const provider = new ethers.providers.JsonRpcProvider(
  'https://mainnet.infura.io/v3/YOUR_PROJECT_ID'
);

// Define the contract address and ABI
const contractAddress = 'CONTRACT_ADDRESS';
const contractAbi = JSON.parse(fs.readFileSync('CONTRACT_ABI.json', 'utf8'));

// Create a new instance of the contract
const contract = new ethers.Contract(contractAddress, contractAbi, provider);

// Function to send transaction
async function sendTransaction() {
  try {
    const account = ethers.Wallet.createRandom().connect(provider);
    const txCount = await account.getTransactionCount();
    const rawTx = {
      nonce: txCount.toString(),
      gasLimit: ethers.utils.hexlify(20000),
      gasPrice: ethers.utils.hexlify(20e9), // 20 Gwei
      to: contractAddress,
      value: '0',
      data: '0x' + contract.interface.encodeFunctionData('yourMethod', ['arg1', 'arg2']),
    };
    const signedTx = await account.signTransaction(rawTx);
    const txHash = await provider.sendTransaction(signedTx.rawTransaction);
    console.log(txHash);
  } catch (error) {
    console.error(error);
  }
}

// Call a contract method
async function callContract() {
  try {
    const result = await contract.yourMethod('arg1', 'arg2');
    console.log(result);
  } catch (error) {
    console.error(error);
  }
}

// Accept user input and handle it
const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout,
});

async function main() {
  const options = [
    { name: 'send', description: 'Send transaction' },
    { name: 'call', description: 'Call contract method' },
  ];

  readline.question('Select an option:\n1. Send\n2. Call\n> ', async (answer) => {
    switch (parseInt(answer)) {
      case 1:
        await sendTransaction();
        break;
      case 2:
        const method = await readline.question('Enter contract method name: ');
        const args = await readline.question('Enter function arguments separated by space: ');
        await callContract(method, args.split(' '));
        break;
      default:
        console.log('Invalid option');
    }
  });
}

main();